const j = $input.first().json;
function pick(){ for (const k of arguments){ if (j[k] != null && j[k] !== '') return j[k]; } return ''; }

let senderEmail = '';
let senderName = '';
const fromRaw = String(pick('From','from','fromEmail') || '');
const m = fromRaw.match(/^(.*?)<([^>]+)>/);
if (m) { senderName = m[1].replace(/"/g,'').trim(); senderEmail = m[2].trim(); }
else { senderEmail = fromRaw.trim(); }
if (j.from && typeof j.from === 'object' && j.from.value && j.from.value[0]) {
  senderEmail = j.from.value[0].address || senderEmail;
  senderName = j.from.value[0].name || senderName;
}
senderEmail = String(senderEmail || '').toLowerCase();
if (!senderName) senderName = (senderEmail.split('@')[0] || 'there');
senderName = senderName.replace(/,/g, ' ').trim();
const firstName = (senderName.split(' ')[0] || 'there');

const subject = String(pick('Subject','subject') || '(no subject)');
const body = String(pick('text','textPlain','snippet','bodyPlain') || '');
const threadId = String(pick('threadId','threadID') || '');
const messageId = String(pick('id','messageId') || '');

return [{ json: { subject, body, senderEmail, senderName, firstName, threadId, messageId } }];

const item = $input.first().json;
const raw = item.text ?? item.output ?? item.response ?? (item.message && item.message.content) ?? item.content ?? (typeof item === 'string' ? item : JSON.stringify(item));
let parsed;
try {
  const cleaned = String(raw).trim().replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '');
  parsed = JSON.parse(cleaned);
} catch (e) { parsed = {}; }
const cats = ['Support','Sales','Billing','Complaint','Partnership','Spam'];
const prios = ['CRITICAL','HIGH','MEDIUM','LOW'];
const category = cats.includes(parsed.category) ? parsed.category : 'Support';
const priority = prios.includes(parsed.priority) ? parsed.priority : 'MEDIUM';
const n = $('Normalize Email').first().json;
return [{ json: Object.assign({}, n, { category, priority, confidence: Number(parsed.confidence) || null, classify_reason: parsed.reason || '' }) }];

